public class Solution {
    public long MaximumValueSum(int[] nums, int k, IList<IList<int>> edges) {
        int n = nums.Length;
        List<int>[] g = new List<int>[n];
        for (int i = 0; i < n; i++) {
            g[i] = new List<int>();
        }
        foreach (var edge in edges) {
            int u = edge[0], v = edge[1];
            g[u].Add(v);
            g[v].Add(u);
